mapper.select:
SELECT ssd.*, ssg.seller_name, ssg.goods_title, ssg.goods_url, ssg.goods_pic_url FROM `store_sell_detail` ssd LEFT JOIN `store_seller_goods` ssg ON ssd.goods_id = ssg.id WHERE celebrity_private_id = #{storeSellDetailModel.celebrityPrivateId}
AND ssd.year = #{storeSellDetailModel.year}
AND ssd.month = #{storeSellDetailModel.month}
AND ssg.seller_name like '%${storeSellDetailModel.sellerName}%'
AND ssd.settlement_status = #{storeSellDetailModel.settlementStatus}
ORDER BY `year` DESC, `month` DESC

select ssd.id, ssd.celebrity_private_id, ssd.settlement_id, ssd.goods_id, ssd.year, ssd.month, ssd.goods_code, ssd.code_start_time, ssd.code_end_time, ssd.code_discount_rate, ssd.goods_property, ssd.share_time, ssd.settlement_status, ssd.settlement_amount, ssd.settlement_time, ssd.seller_counselor_id, ssd.seller_counselor_name, ssd.create_by, ssd.create_time, scp.nick_name, scp.account, ssg.goods_pic_url, ssg.goods_title, ssg.seller_name from store_sell_detail ssd left join store_celebrity_private scp on scp.id = ssd.celebrity_private_id left join store_seller_goods ssg on ssg.id = ssd.goods_id
and ssg.seller_name like '%${celebrityPrivateGoodsDetailModel.sellerName}%'
and scp.account like '%${celebrityPrivateGoodsDetailModel.account}%'
and ssd.year = #{celebrityPrivateGoodsDetailModel.year}
and ssd.month = #{celebrityPrivateGoodsDetailModel.month}
and ssd.settlement_status = #{celebrityPrivateGoodsDetailModel.settlementStatus}
and ssd.goods_code = #{celebrityPrivateGoodsDetailModel.goodsCode}
order by ssd.create_time desc
